import{_ as e,o as r,c as i,ak as l}from"./chunks/framework.B_unCYUt.js";const u=JSON.parse('{"title":"RabbitMQ","description":"","frontmatter":{},"headers":[],"relativePath":"Infra-RabbitMQ.md","filePath":"Infra-RabbitMQ.md","lastUpdated":1726992622000}'),t={name:"Infra-RabbitMQ.md"};function h(s,a,n,o,d,c){return r(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="rabbitmq" tabindex="-1">RabbitMQ <a class="header-anchor" href="#rabbitmq" aria-label="Permalink to “RabbitMQ”">​</a></h1><ul><li>官方文档<a href="https://www.rabbitmq.com/tutorials/tutorial-one-python.html" target="_blank" rel="noreferrer">https://www.rabbitmq.com/tutorials/tutorial-one-python.html</a></li></ul><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to “Links”">​</a></h2><ul><li><a href="https://github.com/rabbitmq/rabbitmq-tutorials" target="_blank" rel="noreferrer">GitHub:RabbitMQ Tutorials</a></li><li><a href="https://www.rabbitmq.com/tutorials" target="_blank" rel="noreferrer">RabbitMQ official Tutorials</a></li></ul><p><img src="https://wwfyde.oss-cn-hangzhou.aliyuncs.com/images/20210802140907.png" alt="img"></p><p>Producer sends messages to the &quot;hello&quot; queue. The consumer receives messages from that queue.</p><h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h1><h2 id="quickstart" tabindex="-1">quickstart <a class="header-anchor" href="#quickstart" aria-label="Permalink to “quickstart”">​</a></h2><h2 id="应用场景" tabindex="-1">应用场景 <a class="header-anchor" href="#应用场景" aria-label="Permalink to “应用场景”">​</a></h2><h3 id="消息队列" tabindex="-1">消息队列 <a class="header-anchor" href="#消息队列" aria-label="Permalink to “消息队列”">​</a></h3><h3 id="工作队列" tabindex="-1">工作队列 <a class="header-anchor" href="#工作队列" aria-label="Permalink to “工作队列”">​</a></h3><h3 id="发布订阅" tabindex="-1">发布订阅 <a class="header-anchor" href="#发布订阅" aria-label="Permalink to “发布订阅”">​</a></h3><h1 id="基础语义" tabindex="-1">基础语义 <a class="header-anchor" href="#基础语义" aria-label="Permalink to “基础语义”">​</a></h1><ul><li><p>AMQP(高级消息队列协议):</p><ul><li>一个网络协议: 客户端应用与消息中间件代理者之间进行通信</li><li>消息代理（message brokers）从发布者（publishers）亦称生产者（producers）那儿接收消息，并根据既定的路由规则把接收到的消息发送给处理消息的消费者（consumers）。</li><li>由于AMQP是一个网络协议，所以这个过程中的发布者，消费者，消息代理 可以存在于不同的设备上。</li></ul></li><li><p>broker: 代理者</p></li><li><p>publisher: 发布者</p></li><li><p>producer: 生产者</p></li><li><p>consumer: 消费者</p></li><li><p>worker: 执行者</p></li><li><p>channel: 通道</p></li><li><p>queue: 队列</p></li><li><p>exchange: 交换机</p><ul><li>一个消息分发中心, 交换机的类型决定了路由行为</li></ul></li><li><p>entity/实体: 队列，交换机和绑定统称为AMQP实体（AMQP entities）。</p></li></ul><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to “核心概念”">​</a></h2><p><img src="https://wwfyde.oss-cn-hangzhou.aliyuncs.com/images/202409081341828.png" alt="image-20240908134108125"></p><h3 id="broker" tabindex="-1">Broker <a class="header-anchor" href="#broker" aria-label="Permalink to “Broker”">​</a></h3><p><strong>Broker：</strong>接收客户端链接实体，实现 AMQP 消息队列和路由功能；</p><h3 id="virtual-host" tabindex="-1">Virtual Host <a class="header-anchor" href="#virtual-host" aria-label="Permalink to “Virtual Host”">​</a></h3><p><strong>Virtual Host：</strong>是一个虚拟概念，权限控制的最小单位。一个 Virtual Host 里包含多个 Exchange 和 Queue；</p><h3 id="message-消息" tabindex="-1">Message(消息) <a class="header-anchor" href="#message-消息" aria-label="Permalink to “Message(消息)”">​</a></h3><h3 id="producer-生产者" tabindex="-1">Producer(生产者) <a class="header-anchor" href="#producer-生产者" aria-label="Permalink to “Producer(生产者)”">​</a></h3><h3 id="queue-队列" tabindex="-1">Queue(队列) <a class="header-anchor" href="#queue-队列" aria-label="Permalink to “Queue(队列)”">​</a></h3><h3 id="binding-绑定" tabindex="-1">Binding(绑定) <a class="header-anchor" href="#binding-绑定" aria-label="Permalink to “Binding(绑定)”">​</a></h3><h3 id="routing-key-路由键" tabindex="-1">Routing Key(路由键) <a class="header-anchor" href="#routing-key-路由键" aria-label="Permalink to “Routing Key(路由键)”">​</a></h3><h2 id="items" tabindex="-1">Items <a class="header-anchor" href="#items" aria-label="Permalink to “Items”">​</a></h2><h3 id="消息队列-message-queue" tabindex="-1">消息队列(Message Queue) <a class="header-anchor" href="#消息队列-message-queue" aria-label="Permalink to “消息队列(Message Queue)”">​</a></h3><h4 id="多维解释" tabindex="-1">多维解释 <a class="header-anchor" href="#多维解释" aria-label="Permalink to “多维解释”">​</a></h4><ul><li>消息队列的本质功能是在分布式系统中进行异步通信，它允许应用程序通过队列发送和接收消息。</li><li>消息队列的主要功能包括： <ul><li>异步处理：消息队列允许用户把一个任务放入队列，然后不必实时等待结果就可以继续执行其他任务。</li><li>解耦：消息队列可以在系统的各个组成部分之间提供一个解耦的接口。这意味着发送和接收消息的应用程序不需要同时进行。</li><li>削峰填谷：在高流量的系统中，消息队列可以作为一个缓冲，帮助系统应对瞬时的大流量。</li><li>可靠性：如果一个处理消息的进程失败，消息队列可以保证消息不会丢失，当进程恢复后可以继续处理。</li></ul></li></ul><h2 id="amqp" tabindex="-1">AMQP <a class="header-anchor" href="#amqp" aria-label="Permalink to “AMQP”">​</a></h2><p><img src="https://wwfyde.oss-cn-hangzhou.aliyuncs.com/images/20210820155336.png" alt="Publish path from publisher to consumer via exchange and queue"></p><h1 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to “最佳实践”">​</a></h1><h2 id="消息确认与重试机制" tabindex="-1">消息确认与重试机制 <a class="header-anchor" href="#消息确认与重试机制" aria-label="Permalink to “消息确认与重试机制”">​</a></h2><h2 id="消息持久化" tabindex="-1">消息持久化 <a class="header-anchor" href="#消息持久化" aria-label="Permalink to “消息持久化”">​</a></h2><h2 id="监控和日志记录" tabindex="-1">监控和日志记录 <a class="header-anchor" href="#监控和日志记录" aria-label="Permalink to “监控和日志记录”">​</a></h2><h2 id="消息处理顺序性" tabindex="-1">消息处理顺序性 <a class="header-anchor" href="#消息处理顺序性" aria-label="Permalink to “消息处理顺序性”">​</a></h2><h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to “常见问题”">​</a></h1>',37)])])}const m=e(t,[["render",h]]);export{u as __pageData,m as default};
